import { Product, User, SiteSettings, AdminUser } from '../types';

// Connection details
const SUPABASE_URL = 'https://itwhuiqjnqfumuftydmj.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Iml0d2h1aXFqbnFmdW11ZnR5ZG1qIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzAxNDA5NDIsImV4cCI6MjA4NTcxNjk0Mn0.NvpkJGCgd1I_P2eRI9cgXlsNG9bair_4EhhOfPTcesQ';

export class DatabaseService {
  private supabase: SupabaseClient;

  constructor() {
    this.supabase = createClient(SUPABASE_URL, SUPABASE_KEY);
  }

  async init(): Promise<void> {
    // Supabase client is stateless, no init required
    return Promise.resolve();
  }

  // Products
  async getAllProducts(): Promise<Product[]> {
    try {
      const { data, error } = await this.supabase
        .from('products')
        .select('*');

      if (error) throw error;
      return data as Product[] || [];
    } catch (err) {
      console.error('Supabase Error (getAllProducts):', err);
      // Return empty array to allow App.tsx to seed initial data
      return [];
    }
  }

  async saveProducts(products: Product[]): Promise<void> {
    try {
      // Sync logic: Delete items not present in the new list to maintain consistency with local state
      const { data: existingData } = await this.supabase.from('products').select('id');
      if (existingData) {
        const existingIds = existingData.map((p: any) => p.id);
        const newIds = products.map(p => p.id);
        const idsToDelete = existingIds.filter(id => !newIds.includes(id));

        if (idsToDelete.length > 0) {
          await this.supabase.from('products').delete().in('id', idsToDelete);
        }
      }

      // Upsert new/updated items
      if (products.length > 0) {
        const { error } = await this.supabase
          .from('products')
          .upsert(products);
        if (error) throw error;
      }
    } catch (err) {
      console.error('Supabase Error (saveProducts):', err);
    }
  }

  // Users
  async getAllUsers(): Promise<User[]> {
    try {
      const { data, error } = await this.supabase
        .from('users')
        .select('*');

      if (error) throw error;
      return data as User[] || [];
    } catch (err) {
      console.error('Supabase Error (getAllUsers):', err);
      return [];
    }
  }

  async saveUser(user: User): Promise<void> {
    try {
      const { error } = await this.supabase
        .from('users')
        .upsert(user);

      if (error) throw error;
    } catch (err) {
      console.error('Supabase Error (saveUser):', err);
    }
  }

  // Settings
  async getSettings(): Promise<SiteSettings | null> {
    try {
      const { data, error } = await this.supabase
        .from('settings')
        .select('*')
        .eq('id', 'main_config')
