        .from('users')
        .upsert(user);

      if (error) throw error;
    } catch (err) {
      console.error('Supabase Error (saveUser):', err);
    }
  }

  // Settings
  async getSettings(): Promise<SiteSettings | null> {
    try {
      const { data, error } = await this.supabase
        .from('settings')
        .select('*')
        .eq('id', 'main_config')
        .single();

      if (error) {
        // PGRST116 is the error code for "The result contains 0 rows"
        if (error.code !== 'PGRST116') console.error('Supabase Error (getSettings):', error);
        return null;
      }
      return data as SiteSettings;
    } catch (err) {
      console.error('Supabase Error (getSettings):', err);
      return null;
    }
  }

  async saveSettings(settings: SiteSettings): Promise<void> {
    try {
      const { error } = await this.supabase
        .from('settings')
        .upsert({ ...settings, id: 'main_config' });

      if (error) throw error;
    } catch (err) {
      console.error('Supabase Error (saveSettings):', err);
    }
  }

  // Admins
  async getAllAdmins(): Promise<AdminUser[]> {
