        )}

        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} onFundSuccess={handleFundSuccess} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={handleUpdateProducts} onUpdateSettings={handleUpdateSettings} onUpdateAdmins={handleUpdateAdmins} onLogout={() => { setIsAdminLoggedIn(false); localStorage.removeItem('nettoolz_admin_logged'); setCurrentView('home'); }} />}
