import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { Product, User, SiteSettings, AdminUser } from '../types';

// Connection details
const SUPABASE_URL = 'https://itwhuiqjnqfumuftydmj.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Iml0d2h1aXFqbnFmdW11ZnR5ZG1qIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzAxNDA5NDIsImV4cCI6MjA4NTcxNjk0Mn0.NvpkJGCgd1I_P2eRI9cgXlsNG9bair_4EhhOfPTcesQ';

export class DatabaseService {
  private supabase: SupabaseClient;

  constructor() {
    // configured with persistSession: false to avoid localStorage errors in sandboxed environments
    this.supabase = createClient(SUPABASE_URL, SUPABASE_KEY, {
      auth: {
        persistSession: false,
        autoRefreshToken: false,
        detectSessionInUrl: false
      }
    });
  }

  async init(): Promise<boolean> {
    console.log('Initializing Supabase connection...');
    try {
      // Test connection by attempting to count products
      // Using head: true to avoid fetching data, just checking access/existence
      const { error } = await this.supabase.from('products').select('count', { count: 'exact', head: true });

      if (error) {
        // Handle network errors (like Load failed) gracefully
        if (error.message && (error.message.includes('Load failed') || error.message.includes('fetch failed'))) {
           console.warn('Supabase is unreachable (Network/CORS/Blocked). Starting in Offline Mode.');
           return false;
        }

        // Code 42P01 means "relation does not exist" - implying we connected but tables aren't made yet.
        if (error.code === '42P01') {
          console.warn('Supabase Connected! WARNING: Tables do not exist. Please run SQL migrations.');
          return true;
        }

        console.error('Supabase Connection Test Failed:', error.message);
        return false;
      }

      console.log('Supabase Connection Verified Successfully.');
      return true;
    } catch (err) {
      console.warn('Supabase Initialization Exception (Offline Mode):', err);
      return false;
    }
  }

  // Products
  async getAllProducts(): Promise<Product[]> {
    try {
      const { data, error } = await this.supabase
        .from('products')
        .select('*');

      if (error) throw error;
      return data as Product[] || [];
    } catch (err) {
      // Silent fail to offline data
      return [];
    }
  }

  async saveProducts(products: Product[]): Promise<void> {
    try {
      // Sync logic: Delete items not present in the new list to maintain consistency with local state
      const { data: existingData } = await this.supabase.from('products').select('id');
      if (existingData) {
        const existingIds = existingData.map((p: any) => p.id);
        const newIds = products.map(p => p.id);
        const idsToDelete = existingIds.filter(id => !newIds.includes(id));

        if (idsToDelete.length > 0) {
          await this.supabase.from('products').delete().in('id', idsToDelete);
        }
      }

      // Upsert new/updated items
      if (products.length > 0) {
        const { error } = await this.supabase
          .from('products')
          .upsert(products);
        if (error) throw error;
      }
    } catch (err) {
      // Offline mode, ignore sync errors
    }
  }

  // Users
  async getAllUsers(): Promise<User[]> {
    try {
      const { data, error } = await this.supabase
        .from('users')
        .select('*');

      if (error) throw error;
      return data as User[] || [];
    } catch (err) {
      return [];
    }
  }

  async saveUser(user: User): Promise<void> {
    try {
      const { error } = await this.supabase
        .from('users')
        .upsert(user);

      if (error) throw error;
    } catch (err) {
      // Offline mode
    }
  }

  // Settings
  async getSettings(): Promise<SiteSettings | null> {
    try {
      const { data, error } = await this.supabase
        .from('settings')
        .select('*')
        .eq('id', 'main_config')
        .single();

      if (error) {
        // PGRST116 is the error code for "The result contains 0 rows"
        if (error.code !== 'PGRST116') console.error('Supabase Error (getSettings):', error);
        return null;
      }
      return data as SiteSettings;
    } catch (err) {
      return null;
    }
  }

  async saveSettings(settings: SiteSettings): Promise<void> {
    try {
      const { error } = await this.supabase
        .from('settings')
        .upsert({ ...settings, id: 'main_config' });

      if (error) throw error;
    } catch (err) {
      // Offline mode
    }
  }

  // Admins
  async getAllAdmins(): Promise<AdminUser[]> {
    try {
      const { data, error } = await this.supabase
        .from('admins')
        .select('*');

      if (error) throw error;
      return data as AdminUser[] || [];
    } catch (err) {
      return [];
    }
  }

  async saveAdmins(admins: AdminUser[]): Promise<void> {
    try {
      // Sync logic for admins
      const { data: existingData } = await this.supabase.from('admins').select('id');
      if (existingData) {
        const existingIds = existingData.map((a: any) => a.id);
        const newIds = admins.map(a => a.id);
        const idsToDelete = existingIds.filter(id => !newIds.includes(id));

        if (idsToDelete.length > 0) {
          await this.supabase.from('admins').delete().in('id', idsToDelete);
        }
      }

      if (admins.length > 0) {
        const { error } = await this.supabase
          .from('admins')
          .upsert(admins);
        if (error) throw error;
      }
    } catch (err) {
      // Offline mode
    }
  }
}

export const dbService = new DatabaseService();

