  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
